client_script:
frappe.web_form.on('load', function(){
  var user = (frappe.session && frappe.session.user) ? frappe.session.user : null;
  if (!user || user === 'Guest') return;

  var roles = (frappe.boot && frappe.boot.user && frappe.boot.user.roles) ? frappe.boot.user.roles : [];
  var can_select_any_employee = roles.indexOf('HR Manager') !== -1 || roles.indexOf('HR User') !== -1 || roles.indexOf('System Manager') !== -1;

  if (!frappe.web_form.doc.posting_date) {
    frappe.web_form.set_value('posting_date', frappe.datetime.get_today());
  }

  frappe.call({
    method: 'frappe.client.get_value',
    args: {
      doctype: 'Employee',
      filters: { user_id: user, status: 'Active' },
      fieldname: ['name', 'employee_name', 'department']
    },
    callback: function(r){
      if (!r || !r.message) return;
      if (!frappe.web_form.doc.employee) {
        frappe.web_form.set_value('employee', r.message.name);
      }
      if (!frappe.web_form.doc.employee_name && r.message.employee_name) {
        frappe.web_form.set_value('employee_name', r.message.employee_name);
      }
      if (!frappe.web_form.doc.department && r.message.department) {
        frappe.web_form.set_value('department', r.message.department);
      }
      if (!can_select_any_employee) {
        frappe.web_form.set_df_property('employee', 'read_only', 1);
      }

      // Force branded KYA layout once core fields are ready.
      setTimeout(function() {
        if (window.kyaRestructureForm) window.kyaRestructureForm();
      }, 150);
    }
  });
});
